class Solution:
    def getLeastFrequentDigit(self, n):
        s = str(n)
        best_digit = -1
        best_count = None
        for d in range(10):
            c = s.count(str(d))
            if c == 0:
                continue
            if best_count is None or c < best_count:
                best_count = c
                best_digit = d
        return best_digit

