var getLeastFrequentDigit = function(n) {
    const cnt = {};
    for (const ch of String(n)) cnt[ch] = (cnt[ch] || 0) + 1;
    let bestDigit = -1, bestCount = Infinity;
    for (let d = 0; d <= 9; d++) {
        const c = cnt[String(d)] || 0;
        if (c === 0) continue;
        if (c < bestCount) { bestCount = c; bestDigit = d; }
    }
    return bestDigit;
};
